  (700, 'profile.stages.second-string.description', gh_lang_pack(
    $gh$The bond grows beyond one moment of leverage and becomes a useful social connection.$gh$, $gh$Связь выходит за пределы одного рычага влияния и становится полезным социальным контактом.$gh$, $gh$Зв'язок виходить за межі одного важеля впливу й стає корисним соціальним контактом.$gh$, $gh$Връзката излиза отвъд един момент на влияние и става полезна социална връзка.$gh$, $gh$Веза прераста један тренутак утицаја и постаје корисна друштвена веза.$gh$, $gh$El vínculo crece más allá de un momento de ventaja y se vuelve conexión social útil.$gh$, $gh$Le lien dépasse un simple levier et devient une relation sociale utile.$gh$, $gh$Die Bindung wächst über einen einzelnen Hebel hinaus und wird zu einer nützlichen sozialen Verbindung.$gh$, $gh$Il legame supera un singolo momento di leva e diventa un contatto sociale utile.$gh$, $gh$O vínculo cresce além de um momento de vantagem e vira conexão social útil.$gh$, $gh$Legătura trece dincolo de un singur moment de pârghie și devine o conexiune socială utilă.$gh$, $gh$הקשר גדל מעבר לרגע אחד של מנוף והופך לחיבור חברתי שימושי.$gh$, $gh$تنمو الصلة أبعد من لحظة نفوذ واحدة وتصبح رابطاً اجتماعياً مفيداً.$gh$, $gh$پیوند از یک لحظه اهرم فراتر می‌رود و به ارتباط اجتماعی سودمند بدل می‌شود.$gh$, $gh$رشتہ ایک لمحے کے دباؤ سے آگے بڑھ کر مفید سماجی تعلق بن جاتا ہے۔$gh$, $gh$बंधन एक पल के दबाव से आगे बढ़कर उपयोगी सामाजिक संबंध बनता है।$gh$, $gh$बंध एका प्रभावाच्या क्षणापलीकडे जाऊन उपयोगी सामाजिक नाते बनतो.$gh$, $gh$सम्बन्ध एउटा प्रभावको क्षणभन्दा पर बढेर उपयोगी सामाजिक जडान बन्छ।$gh$, $gh$বন্ধন এক মুহূর্তের প্রভাবের বাইরে গিয়ে কাজে লাগা সামাজিক সংযোগ হয়।$gh$, $gh$สายสัมพันธ์เติบโตเกินแรงต่อรองชั่วขณะ กลายเป็นความสัมพันธ์ทางสังคมที่ใช้ได้จริง$gh$, $gh$Ο δεσμός ξεπερνά μια στιγμή μόχλευσης και γίνεται χρήσιμη κοινωνική σύνδεση.$gh$, $gh$Կապը անցնում է մեկ լծակի պահից այն կողմ և դառնում օգտակար սոցիալական կապ։$gh$, $gh$კავშირი ერთ გავლენის წამს სცდება და სასარგებლო სოციალურ კავშირად იქცევა.$gh$, $gh$유대는 한 번의 지렛대를 넘어 유용한 사회적 연결이 된다.$gh$, $gh$絆は一度の取引材料を超え、有用な社会的つながりになる。$gh$, $gh$关系超越一次筹码，成为有用的社会联系。$gh$
  ))
),
entity_packs AS (
  SELECT entity_id, jsonb_object_agg(field_name, pack) AS pack
    FROM raw_packs
   GROUP BY entity_id
)
UPDATE entities AS entity
   SET i18n = COALESCE(entity.i18n, '{}'::jsonb) || entity_packs.pack
  FROM entity_packs
 WHERE entity.id = entity_packs.entity_id;
